# app.py - Main application (interface layer)
from flask import Flask, request, jsonify
from ai_service import AIService

app = Flask(__name__)
ai_service = AIService()

@app.route('/predict', methods=['POST'])
def predict():
    try:
        input_data = request.json.get('data')
        if not input_data:
            return jsonify({'error': 'No input data provided'}), 400

        result = ai_service.process(input_data)
        return jsonify({'prediction': result})
    except Exception as e:
        return jsonify({'error': 'Prediction failed', 'details': str(e)}), 500

if __name__ == '__main__':
    app.run()

# ai_service.py - Business logic layer (separate from interface)
class AIService:
    def __init__(self):
        self.model = load_model()  # Load AI model

    def process(self, input_data):
        try:
            cleaned_data = preprocess(input_data)
            prediction = self.model.predict(cleaned_data)
            return postprocess(prediction)
        except Exception as e:
            handle_fallback(e)  # Graceful degradation
